import{_ as e,o,c as i,a2 as d}from"./chunks/framework.Bk_3gXAz.js";const u=JSON.parse('{"title":"tailwind-mastery","description":"Master Tailwind CSS utilities, responsive design, and accessibility patterns. Use when the user mentions \\"Tailwind\\", \\"Tailwind CSS\\", \\"utility-first\\", \\"responsive design\\", \\"dark mode\\", \\"focus-visible\\", \\"motion-reduce\\", or \\"Tailwind v4\\". Covers utility patterns, layout, responsive design, components, accessibility, and performance. For React styling, see react-mastery. For design systems, see refactoring-ui.","frontmatter":{"title":"tailwind-mastery","name":"tailwind-mastery","description":"Master Tailwind CSS utilities, responsive design, and accessibility patterns. Use when the user mentions \\"Tailwind\\", \\"Tailwind CSS\\", \\"utility-first\\", \\"responsive design\\", \\"dark mode\\", \\"focus-visible\\", \\"motion-reduce\\", or \\"Tailwind v4\\". Covers utility patterns, layout, responsive design, components, accessibility, and performance. For React styling, see react-mastery. For design systems, see refactoring-ui.","license":"MIT","metadata":{"author":"todyle","version":"1.0.0"}},"headers":[],"relativePath":"skills/tailwind-mastery.md","filePath":"skills/tailwind-mastery.md"}'),s={name:"skills/tailwind-mastery.md"};function r(n,t,a,c,l,g){return o(),i("div",null,[...t[0]||(t[0]=[d('<h1 id="tailwind-css-mastery-framework" tabindex="-1">Tailwind CSS Mastery Framework <a class="header-anchor" href="#tailwind-css-mastery-framework" aria-label="Permalink to &quot;Tailwind CSS Mastery Framework&quot;">​</a></h1><p>A comprehensive guide to building production UIs with Tailwind CSS utilities, responsive patterns, accessibility, and performance optimization. Apply these principles when styling web applications, building component libraries, implementing dark mode, or optimizing CSS output.</p><h2 id="core-principle" tabindex="-1">Core Principle <a class="header-anchor" href="#core-principle" aria-label="Permalink to &quot;Core Principle&quot;">​</a></h2><p><strong>Utility-first CSS means composing designs directly in HTML with small, single-purpose classes.</strong> Instead of writing custom CSS for every component, you combine utilities (<code>flex</code>, <code>items-center</code>, <code>p-4</code>, <code>text-lg</code>) to build designs. This eliminates naming fatigue, CSS specificity wars, and dead CSS. Every class you see describes exactly what it does.</p><p><strong>The foundation:</strong> Tailwind works because most CSS is repeated — the same spacing, colors, and typography patterns appear throughout an application. Utilities express these patterns directly. The build tool strips unused classes, resulting in tiny production CSS. The key is working within Tailwind&#39;s design system (spacing scale, color palette, breakpoints) rather than escaping it with arbitrary values.</p><h2 id="scoring" tabindex="-1">Scoring <a class="header-anchor" href="#scoring" aria-label="Permalink to &quot;Scoring&quot;">​</a></h2><p><strong>Goal: 10/10.</strong> When reviewing Tailwind code, rate 0-10:</p><ul><li><strong>9-10:</strong> Mobile-first responsive, dark mode, focus-visible, motion-reduce, semantic color naming, consistent spacing scale</li><li><strong>7-8:</strong> Good utility usage with minor issues (arbitrary values for scale values, missing dark mode, inconsistent spacing)</li><li><strong>5-6:</strong> Working styles but overusing @apply, arbitrary values abundant, no responsive design</li><li><strong>3-4:</strong> Tailwind as CSS-in-HTML (every value arbitrary), no dark mode, no accessibility</li><li><strong>1-2:</strong> Fighting Tailwind with custom CSS, important! everywhere, no design system</li></ul><h2 id="the-tailwind-mastery-framework" tabindex="-1">The Tailwind Mastery Framework <a class="header-anchor" href="#the-tailwind-mastery-framework" aria-label="Permalink to &quot;The Tailwind Mastery Framework&quot;">​</a></h2><p>Six disciplines for production Tailwind CSS:</p><h3 id="_1-utility-patterns-design-system" tabindex="-1">1. Utility Patterns &amp; Design System <a class="header-anchor" href="#_1-utility-patterns-design-system" aria-label="Permalink to &quot;1. Utility Patterns &amp; Design System&quot;">​</a></h3><p><strong>Core concept:</strong> Use Tailwind&#39;s design tokens (spacing scale, color palette, font sizes) instead of arbitrary values. The spacing scale (4px increments: <code>p-1</code>=4px, <code>p-2</code>=8px, <code>p-4</code>=16px) creates visual consistency. Extend the design system via <code>tailwind.config.js</code> for brand colors, not with arbitrary <code>[]</code> values.</p><p><strong>Why it works:</strong> Constraints breed consistency. When everyone uses <code>gap-4</code> instead of <code>gap-[15px]</code>, spacing is uniform across the entire application. The predefined scale means fewer design decisions and faster development. Custom theme values (<code>bg-primary</code>, <code>text-success</code>) encode brand semantics.</p><p><strong>Key insights:</strong></p><ul><li>Spacing scale: <code>p-1</code>=4px, <code>p-2</code>=8px, <code>p-4</code>=16px, <code>p-6</code>=24px, <code>p-8</code>=32px</li><li>Use scale values over arbitrary: <code>gap-6</code> not <code>gap-[23px]</code></li><li>Color opacity: <code>bg-black/50</code> (50% opacity) instead of separate <code>opacity-50</code></li><li><code>space-y-4</code> for vertical lists — adds margin between children</li><li><code>size-6</code> shorthand for equal width+height (Tailwind v4)</li><li><code>shrink-0</code> shorthand (v4) instead of <code>flex-shrink-0</code></li><li>Extend theme for brand colors: <code>bg-primary</code>, <code>text-cta</code>, <code>border-success</code></li><li><code>bg-linear-to-r</code> (v4) replaces <code>bg-gradient-to-r</code></li></ul><p><strong>Code applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Pattern</th><th>Example</th></tr></thead><tbody><tr><td><strong>Spacing</strong></td><td>Scale values</td><td><code>p-4 m-6 gap-8</code></td></tr><tr><td><strong>Color opacity</strong></td><td>Slash syntax</td><td><code>bg-black/50 text-white/80</code></td></tr><tr><td><strong>List spacing</strong></td><td>space-y</td><td><code>&lt;div class=&quot;space-y-4&quot;&gt;</code></td></tr><tr><td><strong>Brand color</strong></td><td>Theme extend</td><td><code>bg-primary text-on-primary</code></td></tr><tr><td><strong>Square element</strong></td><td>size utility</td><td><code>size-8</code> (= <code>h-8 w-8</code>)</td></tr><tr><td><strong>Gradient</strong></td><td>bg-linear (v4)</td><td><code>bg-linear-to-r from-blue-500 to-purple-500</code></td></tr></tbody></table><h3 id="_2-layout" tabindex="-1">2. Layout <a class="header-anchor" href="#_2-layout" aria-label="Permalink to &quot;2. Layout&quot;">​</a></h3><p><strong>Core concept:</strong> Container with <code>max-w-7xl mx-auto</code> for content width. <code>flex</code> for one-dimensional, <code>grid</code> for two-dimensional layouts. Responsive padding <code>px-4 md:px-6 lg:px-8</code>. Container queries <code>@container</code> for component-level responsiveness.</p><p><strong>Why it works:</strong> <code>max-w-7xl mx-auto</code> prevents content from stretching to unreadable widths on large screens. <code>gap-*</code> replaces manual margins on grid/flex children, simplifying layout code. Container queries enable components to respond to their container size rather than the viewport — essential for reusable components.</p><p><strong>Key insights:</strong></p><ul><li><code>max-w-7xl mx-auto px-4</code> for main content container</li><li><code>flex items-center justify-between</code> — most common header pattern</li><li><code>grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6</code> for responsive grid</li><li><code>gap-*</code> on flex/grid containers, not margins on children</li><li>Responsive padding: <code>px-4 sm:px-6 lg:px-8</code></li><li><code>@container</code> + <code>@lg:grid-cols-2</code> for component-level responsive (v3.2+)</li><li>Negative margins sparingly: <code>-mt-8</code> for intentional overlapping effects</li></ul><p><strong>Code applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Pattern</th><th>Example</th></tr></thead><tbody><tr><td><strong>Container</strong></td><td>max-w + padding</td><td><code>&lt;div class=&quot;max-w-7xl mx-auto px-4 sm:px-6 lg:px-8&quot;&gt;</code></td></tr><tr><td><strong>Flex row</strong></td><td>items-center</td><td><code>&lt;nav class=&quot;flex items-center justify-between h-16&quot;&gt;</code></td></tr><tr><td><strong>Grid</strong></td><td>Responsive cols</td><td><code>&lt;div class=&quot;grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6&quot;&gt;</code></td></tr><tr><td><strong>Container query</strong></td><td>@container</td><td><code>&lt;div class=&quot;@container&quot;&gt;&lt;div class=&quot;@lg:grid-cols-2&quot;&gt;</code></td></tr></tbody></table><h3 id="_3-responsive-design" tabindex="-1">3. Responsive Design <a class="header-anchor" href="#_3-responsive-design" aria-label="Permalink to &quot;3. Responsive Design&quot;">​</a></h3><p><strong>Core concept:</strong> Mobile-first — write base styles for mobile, add breakpoints for larger screens via <code>sm:</code>, <code>md:</code>, <code>lg:</code>, <code>xl:</code>, <code>2xl:</code> prefixes. Test at all breakpoints: 320, 375, 768, 1024, 1280, 1536px. Use <code>hidden md:block</code> for visibility control.</p><p><strong>Why it works:</strong> Mobile-first ensures the smallest, most constrained screens get attention first. Adding complexity for larger screens is natural — hiding sidebar on mobile, showing it on desktop. This approach also results in smaller CSS because mobile styles don&#39;t need breakpoint prefixes.</p><p><strong>Key insights:</strong></p><ul><li>Base styles = mobile. Breakpoints add desktop enhancements</li><li><code>text-sm md:text-base lg:text-lg</code> — progressive text sizing</li><li><code>hidden md:flex</code> — hide on mobile, show on desktop</li><li><code>flex-col md:flex-row</code> — stack on mobile, row on desktop</li><li>Test at 320px (smallest iPhone SE) — don&#39;t ignore small screens</li><li><code>aspect-video</code> with <code>object-cover</code> for responsive media</li><li><code>srcset</code> with <code>sizes</code> attribute for responsive images (HTML, not Tailwind)</li></ul><p><strong>Code applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Pattern</th><th>Example</th></tr></thead><tbody><tr><td><strong>Mobile-first</strong></td><td>Base + breakpoint</td><td><code>&lt;h1 class=&quot;text-2xl md:text-4xl lg:text-5xl&quot;&gt;</code></td></tr><tr><td><strong>Show/hide</strong></td><td>hidden + display</td><td><code>&lt;nav class=&quot;hidden md:flex&quot;&gt;</code> (mobile menu alternative)</td></tr><tr><td><strong>Stack → row</strong></td><td>Direction change</td><td><code>&lt;div class=&quot;flex flex-col md:flex-row gap-4&quot;&gt;</code></td></tr><tr><td><strong>Responsive image</strong></td><td>aspect + object</td><td><code>&lt;img class=&quot;aspect-video object-cover w-full rounded-xl&quot;&gt;</code></td></tr><tr><td><strong>Responsive padding</strong></td><td>Breakpoint padding</td><td><code>&lt;main class=&quot;px-4 sm:px-6 lg:px-8&quot;&gt;</code></td></tr></tbody></table><h3 id="_4-components" tabindex="-1">4. Components <a class="header-anchor" href="#_4-components" aria-label="Permalink to &quot;4. Components&quot;">​</a></h3><p><strong>Core concept:</strong> Buttons need consistent sizing (<code>px-4 py-2</code>), minimum touch targets on mobile (<code>min-h-[44px]</code>), loading states, and proper icon button labels. Cards use <code>rounded-lg shadow-md</code> with hover feedback. Forms need visible focus indicators (<code>focus:ring-2</code>), disabled states, and keyboard accessibility.</p><p><strong>Why it works:</strong> Consistency in component sizing creates visual rhythm. Touch targets of 44px minimum (Apple HIG standard) prevent frustrating tap misses on mobile. Focus indicators are essential for keyboard navigation and WCAG compliance. Interactive elements must provide feedback — hover, focus, active, disabled states.</p><p><strong>Key insights:</strong></p><ul><li>Buttons: <code>px-4 py-2 rounded-lg font-medium transition-colors</code></li><li>Touch targets: <code>min-h-[44px] min-w-[44px]</code> on all interactive mobile elements</li><li>Loading button: <code>disabled + opacity-50 + spinner icon</code></li><li>Cards: <code>rounded-2xl shadow-lg p-6 hover:shadow-xl transition-shadow</code></li><li>Inputs: <code>h-10 w-full px-3 rounded-md border focus:ring-2 focus:ring-blue-500</code></li><li>Disabled: <code>disabled:opacity-50 disabled:cursor-not-allowed</code></li><li>Icon buttons: always include <code>aria-label</code></li></ul><p><strong>Code applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Pattern</th><th>Example</th></tr></thead><tbody><tr><td><strong>Button</strong></td><td>Standard</td><td><code>&lt;button class=&quot;px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors&quot;&gt;</code></td></tr><tr><td><strong>Touch target</strong></td><td>Mobile minimum</td><td><code>&lt;button class=&quot;min-h-[44px] min-w-[44px]&quot;&gt;</code></td></tr><tr><td><strong>Card</strong></td><td>Hover feedback</td><td><code>&lt;div class=&quot;rounded-2xl shadow-lg p-6 hover:shadow-xl transition-shadow&quot;&gt;</code></td></tr><tr><td><strong>Input</strong></td><td>Focus ring</td><td><code>&lt;input class=&quot;h-10 px-3 rounded-md border focus:ring-2 focus:ring-blue-500&quot;&gt;</code></td></tr><tr><td><strong>Disabled</strong></td><td>Opacity + cursor</td><td><code>&lt;button disabled class=&quot;disabled:opacity-50 disabled:cursor-not-allowed&quot;&gt;</code></td></tr><tr><td><strong>Icon button</strong></td><td>aria-label</td><td><code>&lt;button aria-label=&quot;Close&quot;&gt;&lt;XIcon class=&quot;size-5&quot;/&gt;&lt;/button&gt;</code></td></tr></tbody></table><h3 id="_5-accessibility" tabindex="-1">5. Accessibility <a class="header-anchor" href="#_5-accessibility" aria-label="Permalink to &quot;5. Accessibility&quot;">​</a></h3><p><strong>Core concept:</strong> <code>sr-only</code> for screen reader text, <code>focus-visible:ring-2</code> for keyboard-only focus indicators, <code>motion-reduce:animate-none</code> for motion sensitivity, semantic HTML always. Accessibility is not optional — it&#39;s a legal requirement in many jurisdictions.</p><p><strong>Why it works:</strong> <code>focus-visible</code> shows focus rings only for keyboard users (not mouse clicks), improving both aesthetics and accessibility. <code>motion-reduce</code> respects OS-level reduced motion preferences — essential for users with vestibular disorders. <code>sr-only</code> provides context to screen readers without affecting visual design.</p><p><strong>Key insights:</strong></p><ul><li><code>sr-only</code> for text visible only to screen readers</li><li><code>focus-visible:ring-2</code> instead of <code>focus:ring-2</code> — keyboard-only focus</li><li><code>motion-reduce:animate-none</code> respects prefers-reduced-motion</li><li><code>motion-reduce:transition-none</code> for transition-heavy components</li><li>Never <code>outline-none</code> without a replacement focus indicator</li><li>Always <code>aria-label</code> on icon-only buttons</li><li>Dark mode: <code>dark:bg-gray-900 dark:text-gray-100</code> — ensure sufficient contrast</li><li>SVG explicit dimensions: <code>&lt;svg class=&quot;size-6&quot; width=&quot;24&quot; height=&quot;24&quot;&gt;</code> to prevent layout shift</li></ul><p><strong>Code applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Pattern</th><th>Example</th></tr></thead><tbody><tr><td><strong>Screen reader</strong></td><td>sr-only</td><td><code>&lt;span class=&quot;sr-only&quot;&gt;Close menu&lt;/span&gt;</code></td></tr><tr><td><strong>Keyboard focus</strong></td><td>focus-visible</td><td><code>&lt;button class=&quot;focus-visible:ring-2 focus-visible:ring-blue-500&quot;&gt;</code></td></tr><tr><td><strong>Reduced motion</strong></td><td>motion-reduce</td><td><code>&lt;div class=&quot;animate-pulse motion-reduce:animate-none&quot;&gt;</code></td></tr><tr><td><strong>Dark mode</strong></td><td>dark: prefix</td><td><code>&lt;div class=&quot;bg-white dark:bg-gray-900 text-gray-900 dark:text-gray-100&quot;&gt;</code></td></tr><tr><td><strong>Icon a11y</strong></td><td>aria-label</td><td><code>&lt;button aria-label=&quot;Delete item&quot;&gt;&lt;TrashIcon class=&quot;size-5&quot;/&gt;&lt;/button&gt;</code></td></tr><tr><td><strong>SVG dims</strong></td><td>Explicit w/h</td><td><code>&lt;svg class=&quot;size-6&quot; width=&quot;24&quot; height=&quot;24&quot;&gt;</code></td></tr></tbody></table><h3 id="_6-performance-configuration" tabindex="-1">6. Performance &amp; Configuration <a class="header-anchor" href="#_6-performance-configuration" aria-label="Permalink to &quot;6. Performance &amp; Configuration&quot;">​</a></h3><p><strong>Core concept:</strong> Configure <code>content</code> paths correctly so Tailwind can tree-shake unused classes. Avoid overusing <code>@apply</code> — it defeats the purpose of utility-first CSS. Use JIT mode (default in v3+) for development performance. Custom utilities in theme config for repeated one-off values.</p><p><strong>Why it works:</strong> Tailwind&#39;s production CSS is tiny because it only includes classes actually used in your source files. Incorrect <code>content</code> configuration results in either missing styles (too narrow) or bloated CSS (too broad). <code>@apply</code> creates abstraction layers that Tailwind&#39;s utility-first approach was designed to eliminate.</p><p><strong>Key insights:</strong></p><ul><li><code>content: [&#39;./src/**/*.{js,ts,jsx,tsx}&#39;]</code> — must cover all template files</li><li><code>@apply</code> sparingly — prefer direct utilities in HTML/JSX</li><li>Custom utilities in <code>tailwind.config.js</code> for repeated arbitrary values</li><li><code>@tailwindcss/forms</code> for consistent form element reset</li><li><code>@tailwindcss/typography</code> (<code>prose</code>) for markdown/CMS content</li><li>Group and Peer for parent/sibling state: <code>group-hover:text-blue-500</code></li><li><code>peer-checked:bg-blue-100</code> for checkbox/radio state styling</li></ul><p><strong>Code applications:</strong></p><table tabindex="0"><thead><tr><th>Context</th><th>Pattern</th><th>Example</th></tr></thead><tbody><tr><td><strong>Content config</strong></td><td>Glob patterns</td><td><code>content: [&#39;./src/**/*.{js,ts,jsx,tsx,html}&#39;]</code></td></tr><tr><td><strong>Custom utility</strong></td><td>Theme extend</td><td><code>extend: { boxShadow: { card: &#39;0 4px 20px rgba(0,0,0,.08)&#39; } }</code></td></tr><tr><td><strong>Plugin</strong></td><td>Official</td><td><code>plugins: [require(&#39;@tailwindcss/forms&#39;), require(&#39;@tailwindcss/typography&#39;)]</code></td></tr><tr><td><strong>Group hover</strong></td><td>Parent state</td><td><code>&lt;div class=&quot;group&quot;&gt;&lt;span class=&quot;group-hover:text-blue-500&quot;&gt;</code></td></tr><tr><td><strong>Peer</strong></td><td>Sibling state</td><td><code>&lt;input class=&quot;peer&quot;&gt;&lt;label class=&quot;peer-checked:font-bold&quot;&gt;</code></td></tr><tr><td><strong>Prose</strong></td><td>Typography</td><td><code>&lt;article class=&quot;prose prose-lg max-w-none dark:prose-invert&quot;&gt;</code></td></tr></tbody></table><h2 id="common-mistakes" tabindex="-1">Common Mistakes <a class="header-anchor" href="#common-mistakes" aria-label="Permalink to &quot;Common Mistakes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Mistake</th><th>Why It Fails</th><th>Fix</th></tr></thead><tbody><tr><td><strong>Arbitrary values for scale values</strong></td><td>Inconsistent spacing/sizing</td><td>Use <code>p-4</code> not <code>p-[15px]</code></td></tr><tr><td><strong>Heavy @apply usage</strong></td><td>Creates CSS abstractions that defeat utility-first</td><td>Use utilities directly in HTML</td></tr><tr><td><strong>No dark mode</strong></td><td>Poor UX in low-light, not respecting OS preference</td><td>Add <code>dark:</code> variants</td></tr><tr><td><strong>outline-none without replacement</strong></td><td>Keyboard users can&#39;t see focus</td><td><code>focus-visible:ring-2</code></td></tr><tr><td><strong>No motion-reduce</strong></td><td>Harms vestibular disorder users</td><td><code>motion-reduce:animate-none</code></td></tr><tr><td><strong>Small touch targets</strong></td><td>Frustrating mobile experience</td><td><code>min-h-[44px]</code> minimum</td></tr><tr><td><strong>Missing content paths</strong></td><td>Styles missing in production</td><td>Verify all template file paths</td></tr><tr><td><strong>Desktop-first approach</strong></td><td>Complex mobile overrides</td><td>Start with mobile, add <code>md:</code> <code>lg:</code></td></tr><tr><td><strong>bg-gradient-to in v4</strong></td><td>Deprecated syntax</td><td>Use <code>bg-linear-to-r</code> in Tailwind v4</td></tr><tr><td><strong>SVGs without explicit dimensions</strong></td><td>Layout shift before CSS loads</td><td>Add <code>width</code> and <code>height</code> attributes</td></tr></tbody></table><h2 id="quick-diagnostic" tabindex="-1">Quick Diagnostic <a class="header-anchor" href="#quick-diagnostic" aria-label="Permalink to &quot;Quick Diagnostic&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Question</th><th>If No</th><th>Action</th></tr></thead><tbody><tr><td>Using Tailwind&#39;s spacing scale?</td><td>Inconsistent spacing</td><td>Replace arbitrary values with scale tokens</td></tr><tr><td>Mobile-first responsive?</td><td>Complex overrides</td><td>Start with mobile base, add breakpoints</td></tr><tr><td>Dark mode implemented?</td><td>Missing OS preference respect</td><td>Add <code>dark:</code> variants for all colors</td></tr><tr><td>Focus indicators visible?</td><td>Keyboard a11y broken</td><td>Add <code>focus-visible:ring-2</code></td></tr><tr><td>Motion preferences respected?</td><td>A11y violation</td><td>Add <code>motion-reduce:</code> variants</td></tr><tr><td>Touch targets ≥44px?</td><td>Mobile tap frustration</td><td>Add <code>min-h-[44px]</code></td></tr><tr><td>Content paths correct?</td><td>Missing production styles</td><td>Audit tailwind.config.js content</td></tr><tr><td>Using semantic colors?</td><td>Hard to rebrand</td><td>Move to <code>bg-primary</code> theme tokens</td></tr><tr><td>Icon buttons labeled?</td><td>Screen reader fails</td><td>Add <code>aria-label</code> to all icon buttons</td></tr><tr><td>SVGs have explicit dimensions?</td><td>Layout shift</td><td>Add <code>width</code> and <code>height</code> attributes</td></tr></tbody></table><h2 id="further-reading" tabindex="-1">Further Reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to &quot;Further Reading&quot;">​</a></h2><ul><li><a href="https://tailwindcss.com/docs" target="_blank" rel="noreferrer">Tailwind CSS Documentation</a> — Official reference</li><li><a href="https://tailwindcss.com/docs/upgrade-guide" target="_blank" rel="noreferrer">Tailwind CSS v4 Migration</a> — v3 to v4 changes</li><li><a href="https://www.refactoringui.com/" target="_blank" rel="noreferrer">Refactoring UI</a> — Design principles from Tailwind creators</li><li><a href="https://tailwindcss.com/docs/typography-plugin" target="_blank" rel="noreferrer">@tailwindcss/typography</a> — Prose styling</li><li><a href="https://heroicons.com/" target="_blank" rel="noreferrer">Heroicons</a> — SVG icons from Tailwind Labs</li></ul><h2 id="about" tabindex="-1">About <a class="header-anchor" href="#about" aria-label="Permalink to &quot;About&quot;">​</a></h2><p>This skill synthesizes patterns from Adam Wathan (Tailwind creator), Steve Schoger (Refactoring UI), and the Tailwind CSS community. For visual design principles, see refactoring-ui. For top-tier web design, see top-design. For React integration, see react-mastery.</p>',60)])])}const h=e(s,[["render",r]]);export{u as __pageData,h as default};
